from flask import Flask, request
import importlib

app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    using importlib to safely import the module
    '''
    module_name = request.args.get('module', 'urllib3')

    # Validate module name contains only safe characters
    if not module_name.isidentifier():
        return "Invalid module name", 400

    try:
        module = importlib.import_module(module_name)
        return getattr(module, '__version__', 'Version not available')
    except ImportError:
        return f"Module '{module_name}' not found", 404

