import pickle
import builtins

ALLOWED_CLASSES = {
    'NoneType': type(None),
    'bool': bool,
    'int': int,
    'float': float,
    'complex': complex,
    'str': str,
    'bytes': bytes,
    'bytearray': bytearray,
    'tuple': tuple,
    'list': list,
    'dict': dict,
    'set': set,
    'frozenset': frozenset,
}

ALLOWED_MODULE_PREFIXES = ('__builtin__', 'builtins', 'copyreg')


class RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        if module in ('copy', 'copyreg', 'builtins', '__builtin__'):
            if name in ALLOWED_CLASSES:
                return ALLOWED_CLASSES[name]
            if module.startswith(ALLOWED_MODULE_PREFIXES):
                return getattr(builtins, name, None)
        raise pickle.UnpicklingError(f"Forbidden: '{module}.{name}'")


def getPickleData(pickled):
    '''
    Return deserialized data using a restricted unpickler
    '''
    try:
        RestrictedUnpickler(pickled).load()
    except (pickle.UnpicklingError, Exception):
        return None

import _pickle as cPickle
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    # Extract the Authorization header (or AuthToken)
    auth_header = headers.get('Authorization') or headers.get('AuthToken')
    if not auth_header:
        return None

    # Strip any "Bearer " or "Token " prefix if present
    for prefix in ('Bearer ', 'Token '):
        if auth_header.startswith(prefix):
            token_b64 = auth_header[len(prefix):]
            break
    else:
        token_b64 = auth_header

    # Decode the Base64-encoded token
    try:
        token_bytes = base64.b64decode(token_b64)
    except Exception:
        return None

    # Deserialize the token using cPickle
    try:
        token = cPickle.loads(token_bytes)
    except Exception:
        return None

    # Validate the token and return its data
    if isinstance(token, dict):
        if token.get('valid'):
            return token.get('data')
        return None
    else:
        # Assume token is an object with 'valid' and 'data' attributes
        if getattr(token, 'valid', False):
            return token.data
        return None

