from flask import request, Flask
import yaml
app = Flask(__name__)

@app.route('/yaml', methods=['GET', 'POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    yaml_data = request.data
    if not yaml_data:
        yaml_data = request.args.get('data', '')

    try:
        parsed_data = yaml.safe_load(yaml_data)
        return parsed_data
    except yaml.YAMLError:
        return 'Invalid YAML data', 400
